__kernel__ void 
lud_diagonal(__global__ float *m, __local__ float *shadow, int matrix_dim, int offset)
{
  int i, j;
  int array_offset = offset * matrix_dim + offset;

  for(i = 0; i < BLOCK_SIZE; i++){
    shadow[i * BLOCK_SIZE + threadIdx.x] = m[array_offset + threadIdx.x];
    array_offset += matrix_dim;
  }
  __syncthreads();

  for(i = 0; i < BLOCK_SIZE - 1; i++) {
    if (threadIdx.x > i){
      for(j = 0; j < i; j++)
        shadow[threadIdx.x * BLOCK_SIZE + i] -= shadow[threadIdx.x * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
      shadow[threadIdx.x * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
    }

    __syncthreads();

    if (threadIdx.x > i){
      for(j = 0; j < i + 1; j++)
        shadow[(i + 1) * BLOCK_SIZE + threadIdx.x] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + threadIdx.x];
    }
    __syncthreads();
  }

  array_offset = (offset + 1) * matrix_dim + offset;
  for(i = 1; BLOCK_SIZE > i; i++){
    m[array_offset + threadIdx.x] = shadow[i * BLOCK_SIZE + threadIdx.x];
    array_offset += matrix_dim;
  }
}

__kernel__ void
lud_perimeter(__global__ float *m, __local__ float *dia, __local__ float *peri_row, __local__ float *peri_col, int matrix_dim, int offset)
{
  int i, j, array_offset;
  int idx;

