__kernel__ void
lud_internal(__global__ float *m, __local__ float *peri_row, __local__ float *peri_col, int matrix_dim, int offset)
{
  int i;
  float sum;

  int global_row_id = offset + (blockIdx.y + 1) * BLOCK_SIZE;
  int global_col_id = offset + (blockIdx.x + 1) * BLOCK_SIZE;

  peri_row[threadIdx.y * BLOCK_SIZE + threadIdx.x] = m[(offset + threadIdx.y) * matrix_dim + global_col_id + threadIdx.x];
  peri_col[threadIdx.y * BLOCK_SIZE + threadIdx.x] = m[(global_row_id + threadIdx.y) * matrix_dim + offset + threadIdx.x];

  __syncthreads();

  sum = 0;
  for (i = 0; i < BLOCK_SIZE; i++)
    sum += peri_col[threadIdx.y * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + threadIdx.x];

  m[(global_row_id + threadIdx.y) * matrix_dim + global_col_id + threadIdx.x] -= sum;
}
